 376 |   const indexPersistence = new IndexPersistence(kv, bm25Index, vectorIndex);
 377 |   // Wire the persistence hook so delete paths can flush BM25/vector
 378 |   // index mutations to disk. Without this, an in-memory remove can be
 379 |   // lost across a hard process exit and the persisted snapshot
 380 |   // restores the deleted entry at next boot.
 381 |   setIndexPersistence(indexPersistence);
 382 | 
