 391 |     );
 392 |   }
 393 |   if (loaded?.vector && vectorIndex && loaded.vector.size > 0) {
 394 |     // Persisted vectors carry whatever dimension the provider had when
 395 |     // they were written. If the active provider declares a different
 396 |     // dimension — or if the on-disk index contains a mix of dimensions
 397 |     // (legacy indexes written before the live-API guard in this PR) —
 398 |     // restoring would silently corrupt search: cosineSimilarity returns
 399 |     // 0 on cross-dim pairs, so affected observations stop matching
 400 |     // anything and recall degrades without an error. Walk every stored
 401 |     // vector instead of trusting the first; refuse to load if anything
 402 |     // is off.
 403 |     const activeDim = embeddingProvider?.dimensions ?? 0;
 404 |     const { mismatches, seenDimensions } =
 405 |       activeDim > 0
 406 |         ? loaded.vector.validateDimensions(activeDim)
 407 |         : { mismatches: [], seenDimensions: new Set<number>() };
 408 | 
 409 |     if (mismatches.length > 0) {
 410 |       const sample = mismatches
 411 |         .slice(0, 5)
 412 |         .map((m) => `${m.obsId} (dim=${m.dim})`)
 413 |         .join(", ");
 414 |       const distinct = Array.from(seenDimensions).sort((a, b) => a - b).join(", ");
 415 |       const dropStale = isDropStaleIndexEnabled();
 416 |       if (dropStale) {
 417 |         console.warn(
 418 |           `[agentmemory] Persisted vector index has ${mismatches.length} of ` +
 419 |             `${loaded.vector.size} vectors with the wrong dimension. Active ` +
 420 |             `provider (${embeddingProvider?.name}) declares ${activeDim}; ` +
 421 |             `dimensions seen on disk: ${distinct}. ` +
 422 |             `AGENTMEMORY_DROP_STALE_INDEX=true is set — discarding the persisted ` +
 423 |             `vectors. Live observations will rebuild the index over time.`,
